package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserParseTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void parse_withNullFile_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, charset, mockFormat);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_withNullFormat_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockFile, charset, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void parse_withValidArguments_returnsCSVParser() throws IOException {
        // Mock FileInputStream construction to avoid actual file IO
        try (MockedConstruction<FileInputStream> ignored = Mockito.mockConstruction(FileInputStream.class,
                (mock, context) -> {
                    // no-op
                })) {
            CSVParser parser = CSVParser.parse(mockFile, charset, mockFormat);
            assertNotNull(parser);
            assertEquals(mockFormat, parser.format);
        }
    }
}
